#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef pair<int,int> pii;typedef pair<int,bool> pib;
const int N=1e6+10,W=1e5,WW=1e5+10;
int fa[N];inline int fnd(int x){return fa[x]==x?x:fnd(fa[x]);}
vector<pii> ed[WW];pib stk[N];int top,dep[N],n,m,siz[N];
inline void BackTo(int lst)
{
	while(top>lst)
	{
		pib u=stk[top--];
		siz[fa[u.first]]-=siz[u.first];
		dep[fa[u.first]]-=u.second;
		fa[u.first]=u.first;
	}
}
inline void ins(int i)
{
	for(pii w:ed[i])
	{
		int u=fnd(w.first),v=fnd(w.second);if(u==v)continue;if(dep[u]<dep[v])swap(u,v);
		stk[++top]={v,dep[u]==dep[v]};siz[u]+=siz[v];fa[v]=u;dep[u]+=(dep[u]==dep[v]);
	}
}
inline void Solve(int l,int r)
{
	if(l==r){if(siz[fnd(1)]==n){printf("%d\n",l);exit(0);}return;}
	int mid=(l+r)>>1,lst=top;
	rep(mid+1,r,i)ins(i);Solve(l,mid);BackTo(lst);
	rep(l,mid,i)ins(i);Solve(mid+1,r);BackTo(lst);
}
int main()
{
	n=read();m=read();
	rep(1,n,i)fa[i]=i,dep[i]=siz[i]=1;
	rep(1,m,i)
	{
		int u=read(),v=read(),w=read();
		ed[w].push_back({u,v});
	}
	Solve(0,W);printf("%d\n",W+1);return 0;
}
